VALUES
  ('real-estate-moex-00824', 'real-estate', 'real-estate-moex-107-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '16歲之甲於騎車上學時，與正在送貨之某公司送貨員乙（30歲）擦撞，並導致路人丙受傷。若 甲與乙均為違規駕駛，下列敘述何者正確？', '["丙僅得請求財產上之損害賠償，不得主張非財產上損害賠償", "甲為有識別能力人，故丙僅得向甲單獨請求損害賠償，不得向甲之父母求償", "我國並無僱傭人責任之規範，僱傭乙之公司不必負損害賠償責任", "甲與乙對丙構成共同侵權行為，均須對丙負連帶損害賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "379f995c766a", "answer_pdf_sha1": "233e5e8ad69f", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00825', 'real-estate', 'real-estate-moex-107-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '針對民法有關撤銷權之規範，下列敘述何者正確？', '["撤銷權僅能對不健全的意思表示為之，不得對法律行為或法律關係為之", "任何撤銷權之行使，均只須以意思表示方式為之，即生法律效果", "撤銷權因一定期間內不行使而消滅，此期間稱為消滅時效", "撤銷權之法律性質與解除權相同，均屬形成權之一種"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "379f995c766a", "answer_pdf_sha1": "233e5e8ad69f", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00826', 'real-estate', 'real-estate-moex-107-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '18歲之甲考取大學後，拿著父母親給的住宿費、生活費至北部求學，擬向乙承租A屋一年。關 於甲乙間租賃契約之效力，下列敘述，何者錯誤？', '["甲為限制行為能力人，故甲所締結之租賃契約無效", "甲得主張關於租賃契約之意思表示，在現代社會中可認為係依其年齡及身分、日常生活所必需 者，例外無須得法定代理人允許，契約仍可成立生效", "甲得提出法定代理人就租屋之書面允許，以使契約成立生效", "乙得定期限催告法定代理人，確答是否承認甲乙間租賃契約，以使契約成立生效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "379f995c766a", "answer_pdf_sha1": "233e5e8ad69f", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00827', 'real-estate', 'real-estate-moex-107-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關贈與之敘述，何者正確？', '["贈與係單獨行為", "贈與以物之交付為要件，於物之交付後，贈與行為才為生效", "經公證之贈與，於贈與物之權利未移轉前，贈與人得隨時撤銷其贈與", "贈與得附有負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "379f995c766a", "answer_pdf_sha1": "233e5e8ad69f", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00828', 'real-estate', 'real-estate-moex-107-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '民法關於法人之規定，下列敘述，何者錯誤？', '["法人可分為財團法人與社團法人", "法人於法令限制內，有享受權利負擔義務之能力。但專屬於自然人之權利義務，不在此限", "法人應設董事與監察人", "法人對於其董事或其他有代表權之人因執行職務所加於他人之損害，與該行為人連帶負賠償之 責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "379f995c766a", "answer_pdf_sha1": "233e5e8ad69f", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00829', 'real-estate', 'real-estate-moex-107-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於人格權保護，下列敘述，何者錯誤？', '["人格權受侵害時，得請求法院除去其侵害；有受侵害之虞時，得請求防止之", "名譽權受侵害時，若法院採取命被告登報道歉作為回復名譽之適當處分，依現行司法實務見 解，仍屬合憲", "債務人因債務不履行，致債權人之人格權受侵害者，不得請求損害賠償", "生命權受侵害時，配偶得請求損害賠償與慰撫金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "379f995c766a", "answer_pdf_sha1": "233e5e8ad69f", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00830', 'real-estate', 'real-estate-moex-107-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於僱傭契約，下列敘述，何者錯誤？', '["僱傭契約之專屬性較低，故僱用人得將其勞務請求權讓與第三人，無需受僱人同意", "受僱人服勞務，因非可歸責於自己之事由致受損害者，得向僱用人請求賠償", "定期之僱傭契約，若當事人之一方遇有重大事由，仍得於期限屆至前終止契約", "受僱人因執行職務，不法侵害他人之權利者，原則上係由僱用人與受僱人連帶負損害賠償責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "379f995c766a", "answer_pdf_sha1": "233e5e8ad69f", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00831', 'real-estate', 'real-estate-moex-107-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列敘述所涉及之物，何者不能單獨作為物權之客體？', '["醫療器材店所販售之大腿義肢", "已被安裝置入大廈內運作的客製化電梯", "區分所有建築物（如大廈）之專有部分", "足以遮風避雨的違章建築物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "379f995c766a", "answer_pdf_sha1": "233e5e8ad69f", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00832', 'real-estate', 'real-estate-moex-107-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲於颱風過後翌日在河邊拾得從國家森林區漂流而下之珍貴紅檜木，乙自甲處竊取之，並將之以 低價出售予不知情之丙。下列敘述，何者正確？', '["甲拾得珍貴漂流木，依民法第802條無主物先占規定，原始取得其所有權", "甲拾得珍貴漂流木，依民法第810條適用關於拾得遺失物規定，負通知及交存該物之義務，無 法立即取得該物所有權", "因天災致國有珍貴林木漂流至國有林區外時，甲得自由撿拾取得所有權，不受民法關於拾得遺 失物規定之限制", "甲因丙取得漂流木所有權而受損害時，得依關於不當得利之規定請求償還價額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "379f995c766a", "answer_pdf_sha1": "233e5e8ad69f", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00833', 'real-estate', 'real-estate-moex-107-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何種權利，得為抵押權之標的物？', '["地上權", "不動產役權", "著作權", "租賃權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "379f995c766a", "answer_pdf_sha1": "233e5e8ad69f", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
